+        count += 1; // Time
+    }
+    count += 1; // ID line
+    if entry.score.is_some() {
+        count += 1; // Score
+    }
+    count += 2; // Separator + body header
+                // Body lines
+    let body = entry.full_body.as_deref().unwrap_or(&entry.body_preview);
+    count += body.lines().count().max(1);
+    count
